        text = str(node)
        stripped = text.strip()
        if not stripped:
            continue
        if stripped in NODE_REPLACEMENTS:
            replacement = NODE_REPLACEMENTS[stripped]
            if text == stripped:
                node.replace_with(replacement)
            else:
                node.replace_with(text.replace(stripped, replacement))
            continue
